TOOL_CATALOGUE = {
    "search_documents": {
        "plans": ["starter", "pro", "enterprise"],
        "definition": {
            "name": "search_documents",
            "description": "Search documents in the tenant's knowledge base.",
            "input_schema": {"type": "object", "properties": {"query": {"type": "string"}}, "required": ["query"]},
        },
    },
    "generate_report": {
        "plans": ["pro", "enterprise"],
        "definition": {
            "name": "generate_report",
            "description": "Generate a PDF report from data.",
            "input_schema": {"type": "object", "properties": {"report_type": {"type": "string"}}, "required": ["report_type"]},
        },
    },
    "bulk_export": {
        "plans": ["enterprise"],
        "definition": {
            "name": "bulk_export",
            "description": "Export all tenant data as a structured archive.",
            "input_schema": {"type": "object", "properties": {"format": {"type": "string", "enum": ["csv", "jsonl"]}}, "required": ["format"]},
        },
    },
}

def get_tools_for_tenant(tenant) -> list[dict]:
    return [
        cfg["definition"]
        for cfg in TOOL_CATALOGUE.values()
        if tenant.plan in cfg["plans"]
    ]

def tenant_can_use_tool(tool_name: str, tenant) -> bool:
    cfg = TOOL_CATALOGUE.get(tool_name)
    return cfg is not None and tenant.plan in cfg["plans"]

from anthropic import Anthropic
import json

client = Anthropic()

def make_tool_executor(tenant):
    """Return a tool executor that always scopes data access to this tenant."""
    import asyncio

    def execute(name: str, inputs: dict) -> str:
        if not tenant_can_use_tool(name, tenant):
            return json.dumps({"error": "not_available_on_your_plan", "tool": name})

        if name == "search_documents":
            # asyncio.run() if the caller is sync; in async context use await
            results = asyncio.run(search_documents(inputs["query"], tenant.tenant_id))
            return json.dumps(results)

        if name == "generate_report":
            # Report generation is scoped to tenant data automatically
            return json.dumps({"report_id": f"rpt_{tenant.tenant_id}_001", "status": "queued"})

        if name == "bulk_export":
            return json.dumps({"export_id": f"exp_{tenant.tenant_id}", "format": inputs.get("format", "jsonl")})

        return json.dumps({"error": "unknown_tool"})

    return execute

def run_agent(message: str, tools: list[dict], tenant) -> str:
    execute = make_tool_executor(tenant)
    messages = [{"role": "user", "content": message}]
    system = (
        f"You are an assistant for {tenant.tenant_id}. "
        f"You have access to the tools listed. Only use tools available on the {tenant.plan} plan."
    )

    while True:
        resp = client.messages.create(
            model="claude-haiku-4-5-20251001",
            max_tokens=800,
            tools=tools,
            system=system,
            messages=messages,
        )
        if resp.stop_reason == "end_turn":
            return next((b.text for b in resp.content if b.type == "text"), "")

        tool_results = []
        for block in resp.content:
            if block.type == "tool_use":
                result = execute(block.name, block.input)
                tool_results.append({"type": "tool_result", "tool_use_id": block.id, "content": result})

        messages += [
            {"role": "assistant", "content": resp.content},
            {"role": "user", "content": tool_results},
        ]
